// ============================================================
// NORMALIZADOR + GENERADOR DE ID HASH
// Detecta columnas flexiblemente sin importar cómo las llamó
// el cliente en su sheet original.
// ============================================================
const crypto = require('crypto');
const items = $input.all();
const plataforma = $vars.PLATAFORMA_NOMBRE || 'Demo';

// Normaliza strings para comparar nombres de columna
const norm = (str) =>
  String(str)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

// Busca el valor del primer key que haga match parcial con alguna de las claves
const findCol = (raw, claves) => {
  for (const clave of claves) {
    const key = Object.keys(raw).find(k => norm(k).includes(clave));
    if (key !== undefined && raw[key] !== undefined && raw[key] !== '') {
      return raw[key];
    }
  }
  return null;
};

const normalized = [];

for (const item of items) {
  const raw = item.json;

  // --- Texto principal (campo más importante) ---
  const textoRaw = findCol(raw, [
    'texto', 'resena', 'comentario', 'review',
    'opinion', 'feedback', 'mensaje', 'descripcion', 'content'
  ]);
  if (!textoRaw || String(textoRaw).trim().length < 5) continue; // saltar filas vacías

  const textoClean = String(textoRaw).trim();

  // --- ID hash (MD5 de texto normalizado, 16 chars) ---
  // Esto garantiza deduplicación cross-fuente: la misma reseña
  // copiada en dos sheets distintos genera el mismo ID.
  const textoParaHash = textoClean.toLowerCase().replace(/\s+/g, ' ');
  const idHash = crypto
    .createHash('md5')
    .update(textoParaHash)
    .digest('hex')
    .substring(0, 16);

  // --- Calificación (1-5) ---
  const calRaw = findCol(raw, [
    'calificacion', 'rating', 'stars', 'estrellas',
    'nota', 'puntuacion', 'score', 'puntaje'
  ]);
  const calificacion = calRaw ? (parseFloat(String(calRaw)) || '') : '';

  // --- Fecha de la reseña ---
  const fechaRaw = findCol(raw, [
    'fecha', 'date', 'created', 'timestamp',
    'creado', 'when', 'publicado'
  ]);
  let fechaResena = '';
  if (fechaRaw) {
    // Intentar parsear y normalizar a YYYY-MM-DD
    try {
      const d = new Date(fechaRaw);
      if (!isNaN(d.getTime())) {
        fechaResena = d.toISOString().split('T')[0];
      } else {
        fechaResena = String(fechaRaw).trim(); // dejar como viene si no parsea
      }
    } catch {
      fechaResena = String(fechaRaw).trim();
    }
  }

  // --- Autor ---
  const autorRaw = findCol(raw, [
    'autor', 'nombre', 'name', 'author',
    'usuario', 'user', 'cliente', 'paciente'
  ]);
  const autor = autorRaw ? String(autorRaw).trim() : 'Anónimo';

  // --- URL origen ---
  const urlRaw = findCol(raw, ['url', 'link', 'enlace', 'fuente_url']);
  const urlOrigen = urlRaw ? String(urlRaw).trim() : '';

  // --- Construir objeto final con schema del Master Sheet ---
  normalized.push({
    json: {
      id:                   idHash,
      texto_original:       textoClean,
      idioma:               'pendiente_deteccion',  // OpenAI lo detecta en Etapa 3
      fuente:               'sheets_existente',
      plataforma:           plataforma,
      fecha_resena:         fechaResena,
      fecha_ingesta:        new Date().toISOString().split('T')[0],
      calificacion_estrella: calificacion,
      autor:                autor,
      url_origen:           urlOrigen,
      estado_procesado:     'pendiente',
      // Campos de IA — vacíos hasta Etapa 3:
      sentimiento:          '',
      categoria:            '',
      score_urgencia:       '',
      entidades_clave:      '',
      resumen_ia:           '',
      accion_sugerida:      ''
    }
  });
}

// Log de diagnóstico (visible en n8n execution log)
console.log(`[VOC Normalizer] Input: ${items.length} filas | Output: ${normalized.length} válidas`);

return normalized;

// ============================================================
// DEDUPLICADOR
// Compara los IDs normalizados contra los IDs ya en el Master.
// Solo pasan las reseñas nuevas.
// ============================================================

// Items del nodo anterior (Master Sheet con IDs existentes)
const masterItems = $input.all();
const existingIds = new Set(
  masterItems
    .map(i => i.json.id)
    .filter(id => id && String(id).trim() !== '')
);

console.log(`[VOC Dedup] IDs en Master: ${existingIds.size}`);

// Items del nodo de normalización
const allNormalized = $('Normalizar — ID + Schema').all();
const nuevas = allNormalized.filter(i => !existingIds.has(i.json.id));

console.log(`[VOC Dedup] Total normalizados: ${allNormalized.length} | Nuevos: ${nuevas.length} | Duplicados omitidos: ${allNormalized.length - nuevas.length}`);

if (nuevas.length === 0) {
  // Retornar señal de "sin novedades" para el nodo IF
  return [{ json: { _voc_empty: true, count: 0, mensaje: 'Sin reseñas nuevas — Master Sheet ya actualizado' } }];
}

return nuevas;
